package main

import (
	"context"
	"net"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"go.flipt.io/flipt/internal/server/auth"
	authstorage "go.flipt.io/flipt/internal/storage/auth"
	"go.flipt.io/flipt/internal/storage/auth/memory"
	authrpc "go.flipt.io/flipt/rpc/flipt/auth"
	"go.uber.org/zap/zaptest"
	"google.golang.org/grpc"
	"google.golang.org/grpc/codes"
	"google.golang.org/grpc/credentials/insecure"
	"google.golang.org/grpc/metadata"
	"google.golang.org/grpc/status"
	"google.golang.org/protobuf/types/known/emptypb"
)

// TestRegression demonstrates the authentication issues in Flipt:
// 1. Cookie-based tokens are not extracted or validated
// 2. There is no mechanism to skip authentication for specific server instances
func TestRegression(t *testing.T) {
	t.Run("CookieBasedTokenExtraction", testCookieBasedTokenExtraction)
	t.Run("ServerLevelAuthenticationBypass", testServerLevelAuthenticationBypass)
}

// testCookieBasedTokenExtraction demonstrates that valid client tokens
// stored in HTTP cookies are rejected when not provided via Authorization header.
// This is the first reported issue.
func testCookieBasedTokenExtraction(t *testing.T) {
	// Create an in-memory authentication store with a valid client token
	authenticator := memory.NewStore()

	clientToken, storedAuth, err := authenticator.CreateAuthentication(
		context.Background(),
		&authstorage.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)
	require.NotEmpty(t, clientToken)
	require.NotNil(t, storedAuth)

	logger := zaptest.NewLogger(t)

	// Create a gRPC server with authentication middleware enabled
	grpcServer := grpc.NewServer(
		grpc.UnaryInterceptor(auth.UnaryInterceptor(logger, authenticator)),
	)
	defer grpcServer.Stop()

	// Register the authentication service
	authServer := auth.NewServer(logger, authenticator)
	authrpc.RegisterAuthenticationServiceServer(grpcServer, authServer)

	// Start the server on a random port
	lis, err := net.Listen("tcp", "127.0.0.1:0")
	require.NoError(t, err)
	defer lis.Close()

	go func() {
		_ = grpcServer.Serve(lis)
	}()

	// Give the server time to start
	time.Sleep(100 * time.Millisecond)

	// Connect a gRPC client
	conn, err := grpc.Dial(
		lis.Addr().String(),
		grpc.WithTransportCredentials(insecure.NewCredentials()),
	)
	require.NoError(t, err)
	defer conn.Close()

	client := authrpc.NewAuthenticationServiceClient(conn)

	// Test 1: Valid token in Authorization header works (baseline)
	t.Run("ValidTokenInAuthorizationHeader", func(t *testing.T) {
		ctx := metadata.AppendToOutgoingContext(
			context.Background(),
			"Authorization", "Bearer "+clientToken,
		)

		resp, err := client.GetAuthenticationSelf(ctx, &emptypb.Empty{})
		assert.NoError(t, err)
		assert.NotNil(t, resp)
		assert.Equal(t, storedAuth.Id, resp.Id)
	})

	// Test 2: Token in cookie is NOT recognized (bug)
	// This test demonstrates the first reported issue:
	// browsers store tokens in cookies under the key 'flipt_client_token',
	// but the middleware only checks the Authorization header.
	t.Run("TokenInCookieIsRejected", func(t *testing.T) {
		// Create a context with the token in a cookie-like metadata format
		// (gRPC uses metadata instead of HTTP cookies, but the pattern is similar)
		// Note: The middleware only looks for "authorization" header, not cookies
		ctx := metadata.AppendToOutgoingContext(
			context.Background(),
			"cookie", "flipt_client_token="+clientToken,
		)

		resp, err := client.GetAuthenticationSelf(ctx, &emptypb.Empty{})

		// This should fail because the middleware doesn't check cookies
		assert.Error(t, err)
		assert.Nil(t, resp)

		// Verify it's an unauthenticated error
		st, ok := status.FromError(err)
		require.True(t, ok)
		assert.Equal(t, codes.Unauthenticated, st.Code())
	})

	// Test 3: Token only in custom header (not Authorization) is also rejected
	// This demonstrates the issue extends to any header except the specific "authorization" header
	t.Run("TokenInCustomHeaderIsRejected", func(t *testing.T) {
		ctx := metadata.AppendToOutgoingContext(
			context.Background(),
			"x-client-token", clientToken,
		)

		resp, err := client.GetAuthenticationSelf(ctx, &emptypb.Empty{})

		assert.Error(t, err)
		assert.Nil(t, resp)

		st, ok := status.FromError(err)
		require.True(t, ok)
		assert.Equal(t, codes.Unauthenticated, st.Code())
	})

	// Test 4: Bearer prefix requirement is strict
	t.Run("TokenWithoutBearerPrefixIsRejected", func(t *testing.T) {
		ctx := metadata.AppendToOutgoingContext(
			context.Background(),
			"Authorization", clientToken, // Missing "Bearer " prefix
		)

		resp, err := client.GetAuthenticationSelf(ctx, &emptypb.Empty{})

		assert.Error(t, err)
		assert.Nil(t, resp)

		st, ok := status.FromError(err)
		require.True(t, ok)
		assert.Equal(t, codes.Unauthenticated, st.Code())
	})
}

// testServerLevelAuthenticationBypass demonstrates that there is no mechanism
// to skip authentication for specific server instances (such as internal servers
// handling delegated authentication flows).
// This is the second reported issue.
func testServerLevelAuthenticationBypass(t *testing.T) {
	// Create two authentication stores
	mainAuthenticator := memory.NewStore()
	internalAuthenticator := memory.NewStore()

	// Create a token in the main store
	mainToken, mainAuth, err := mainAuthenticator.CreateAuthentication(
		context.Background(),
		&authstorage.CreateAuthenticationRequest{Method: authrpc.Method_METHOD_TOKEN},
	)
	require.NoError(t, err)
	require.NotEmpty(t, mainToken)

	logger := zaptest.NewLogger(t)

	// Scenario: We want to run an internal authentication server without auth checks
	// Currently, there's no way to do this - all servers registered with the same
	// gRPC server will have the same authentication middleware applied.

	t.Run("NoWayToSkipAuthenticationForInternalServer", func(t *testing.T) {
		// Create a gRPC server with authentication middleware enforced for ALL services
		grpcServer := grpc.NewServer(
			grpc.UnaryInterceptor(auth.UnaryInterceptor(logger, mainAuthenticator)),
		)
		defer grpcServer.Stop()

		// Register the main authentication service (which needs auth)
		authServer := auth.NewServer(logger, mainAuthenticator)
		authrpc.RegisterAuthenticationServiceServer(grpcServer, authServer)

		// Problem: We also need to register an internal service that should NOT require auth
		// (e.g., for delegated authentication flows), but there's no way to exempt it
		// The middleware is applied at the server level, not the service level.

		// Start the server on a random port
		lis, err := net.Listen("tcp", "127.0.0.1:0")
		require.NoError(t, err)
		defer lis.Close()

		go func() {
			_ = grpcServer.Serve(lis)
		}()

		time.Sleep(100 * time.Millisecond)

		// Connect a client
		conn, err := grpc.Dial(
			lis.Addr().String(),
			grpc.WithTransportCredentials(insecure.NewCredentials()),
		)
		require.NoError(t, err)
		defer conn.Close()

		client := authrpc.NewAuthenticationServiceClient(conn)

		// Even if we wanted to call the auth service without authentication
		// (e.g., for a delegated auth flow or health check), we can't
		// because the middleware is applied to all services globally
		ctx := context.Background()

		resp, err := client.GetAuthenticationSelf(ctx, &emptypb.Empty{})

		// The request is rejected due to authentication
		assert.Error(t, err)
		assert.Nil(t, resp)

		st, ok := status.FromError(err)
		require.True(t, ok)
		assert.Equal(t, codes.Unauthenticated, st.Code())

		// There's no configuration option or mechanism to:
		// 1. Skip authentication for specific services
		// 2. Skip authentication for specific methods
		// 3. Skip authentication for specific server instances
		// All authentication enforcement is all-or-nothing at the gRPC server level
	})

	t.Run("InterceptorCannotBeConfiguredPerService", func(t *testing.T) {
		// The auth middleware is registered globally on the server
		logger := zaptest.NewLogger(t)

		// Current architecture:
		// 1. Single gRPC server is created
		// 2. Authentication interceptor is applied to the gRPC server
		// 3. Multiple services are registered on the same gRPC server
		// 4. The interceptor applies to ALL services (no way to exclude)

		grpcServer := grpc.NewServer(
			// The interceptor is applied here at the server level
			grpc.UnaryInterceptor(auth.UnaryInterceptor(logger, mainAuthenticator)),
		)
		defer grpcServer.Stop()

		// Both services use the same interceptor - there's no per-service configuration
		authServer := auth.NewServer(logger, mainAuthenticator)
		authrpc.RegisterAuthenticationServiceServer(grpcServer, authServer)

		// If we tried to register another service, it would ALSO require authentication
		// There's no way to register a service without authentication requirements

		// This is a limitation for scenarios like:
		// - Health check endpoints that should be public
		// - Delegated authentication servers that should accept unauthenticated requests
		// - Internal metrics endpoints
		// - Diagnostic/debug endpoints

		assert.NotNil(t, authServer) // Just to use the variable
	})
}

